"use client";

import { motion } from "framer-motion";
import { Search, Code2, Palette, BarChart3, Rocket, MessageSquare, Zap, Cpu, Globe, Share2, Layers, Figma, Terminal } from "lucide-react";

const skillCategories = [
    {
        category: "Marketing & Growth",
        icon: Rocket,
        color: "text-orange-500",
        skills: ["Paid Ads (Meta/Google)", "Email Marketing (Klaviyo)", "Social Media Branding", "Growth Hacking", "SEO Strategy", "Funnel Optimization"]
    },
    {
        category: "Product & Operations",
        icon: Layers,
        color: "text-blue-500",
        skills: ["Product Roadmap Strategy", "User Research", "Agile Management", "CRM Workflows", "Business Automations", "Startup Scaling"]
    },
    {
        category: "Design & Creative",
        icon: Palette,
        color: "text-pink-500",
        skills: ["UI/UX Design", "Figma Design Systems", "Brand Identity", "Adobe Creative Suite", "Canva Mastery", "Rapid Prototyping"]
    },
    {
        category: "AI & Tech",
        icon: Cpu,
        color: "text-indigo-500",
        skills: ["Vibe Coding", "AI Workflows Integration", "LLM Prompt Engineering", "NFC/QR Integration", "No-code Development", "TypeScript/React Prep"]
    },
    {
        category: "Content & Community",
        icon: Share2,
        color: "text-emerald-500",
        skills: ["Social Media Strategy", "Copywriting", "Video Scripting", "Community Building", "PR Management", "Brand Consistency"]
    }
];

export default function SkillsPage() {
    return (
        <div className="container mx-auto px-6 py-24 min-h-screen">
            <motion.div
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8 }}
                className="mb-32 text-center max-w-4xl mx-auto"
            >
                <div className="mb-6 inline-flex items-center space-x-2 px-6 py-2 rounded-full glass border border-white/10 uppercase tracking-[0.4em] font-black text-xs text-white/40">
                    Evolution
                </div>
                <h1 className="text-6xl md:text-8xl font-black text-white mb-8 tracking-tighter uppercase leading-tight">
                    A <span className="gradient-text">Complete</span> Stack.
                </h1>
                <p className="text-xl md:text-2xl text-muted leading-relaxed max-w-2xl mx-auto">
                    My skill set is ever-evolving, driven by curiosity and the need to build at speed.
                    I don&apos;t just use tools; I master workflows.
                </p>
            </motion.div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 mt-24">
                {skillCategories.map((cat, index) => (
                    <motion.div
                        key={index}
                        initial={{ opacity: 0, scale: 0.95 }}
                        whileInView={{ opacity: 1, scale: 1 }}
                        viewport={{ once: true }}
                        transition={{ delay: index * 0.1 }}
                        className="p-10 glass border border-white/5 rounded-[40px] group hover:border-white/10 hover:bg-white/5 transition-all relative overflow-hidden h-full"
                    >
                        <div className="flex items-center space-x-6 mb-10 overflow-visible">
                            <div className={`p-4 rounded-3xl bg-white/5 border border-white/10 group-hover:scale-110 group-hover:bg-white/10 transition-all ${cat.color}`}>
                                <cat.icon className="w-8 h-8" />
                            </div>
                            <h2 className="text-3xl font-black text-white uppercase tracking-tight leading-none overflow-visible">{cat.category}</h2>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {cat.skills.map((skill, si) => (
                                <div key={si} className="overflow-visible">
                                    <div className="flex items-center space-x-3 group/item p-4 rounded-2xl hover:bg-white/5 border border-transparent hover:border-white/5 transition-all overflow-visible">
                                        <div className="w-2 h-2 rounded-full bg-white/20 group-hover/item:bg-white/60 transition-colors" />
                                        <span className="text-sm font-bold text-white/70 group-hover/item:text-white transition-colors">{skill}</span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </motion.div>
                ))}
            </div>

            <div className="mt-32 p-16 glass border border-white/10 rounded-[60px] text-center relative overflow-hidden group mb-32">
                <div className="absolute inset-0 bg-gradient-to-r from-indigo-500/10 via-purple-500/10 to-pink-500/10 opacity-0 group-hover:opacity-100 transition-opacity duration-1000 -z-10" />
                <h2 className="text-4xl md:text-6xl font-black text-white mb-10 tracking-tight leading-none uppercase">Tools I <span className="gradient-text">Mastered</span></h2>

                <div className="flex flex-wrap justify-center gap-4 mt-8">
                    {["Figma", "Notion", "Make", "Airtable", "Next.js", "GPT-4", "Claude 3.5", "Linear", "Slack", "Webflow", "Vercel"].map((tool) => (
                        <div key={tool} className="px-6 py-3 rounded-2xl glass border border-white/5 text-xs font-black uppercase tracking-widest text-white/50 hover:text-white hover:border-white/20 transition-all">
                            {tool}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}
